/**
 * backendStrings.ts
 * All user-facing strings generated by the backend, keyed by language.
 * Single source of truth for multilingual backend messages.
 * To add a new language: add a new key to every Record below.
 */

export type SupportedLanguage = 'en' | 'hi';

/** Injected at the top of every LLM system prompt to enforce output language */
export const LANGUAGE_INSTRUCTION: Record<SupportedLanguage, string> = {
  en: 'IMPORTANT: You MUST respond ONLY in English. Do not use any other language.',
  hi: 'महत्वपूर्ण: आपको केवल हिंदी में उत्तर देना है। देवनागरी लिपि का उपयोग करें। किसी भी अन्य भाषा का उपयोग न करें।',
};

