/** Shown when profile is complete and recommendations are ready */
export const PROFILE_COMPLETE_MESSAGE: Record<SupportedLanguage, string> = {
  en: "I have successfully compiled the citizen's profile and identified the top welfare schemes they qualify for. You can review the recommendations and report in the panel on the right.",
  hi: "मैंने सफलतापूर्वक नागरिक की प्रोफ़ाइल तैयार की है और उन शीर्ष कल्याण योजनाओं की पहचान की है जिनके लिए वे पात्र हैं। दाईं ओर के पैनल में सिफारिशें और रिपोर्ट देखें।",
};

/** Shown when recommendation engine throws an error */
export const PROFILE_ERROR_MESSAGE: Record<SupportedLanguage, string> = {
  en: "I have collected the profile details, but encountered an error generating recommendations. Please check your vector database and connection.",
  hi: "मैंने प्रोफ़ाइल विवरण एकत्र किया है, लेकिन सिफारिशें तैयार करते समय एक त्रुटि हुई। कृपया अपना वेक्टर डेटाबेस और कनेक्शन जाँचें।",
};

/** Shown when the full application form is completed */
export const APPLICATION_COMPLETE_MESSAGE: Record<SupportedLanguage, (schemeName: string) => string> = {
  en: (schemeName) =>
    `Great! I have collected all the application details for **${schemeName}** and compiled a professional Casework Application Summary. You can review and print it in the workspace panel.`,
  hi: (schemeName) =>
    `बहुत अच्छा! मैंने **${schemeName}** के लिए सभी आवेदन विवरण एकत्र किए हैं और एक पेशेवर केसवर्क आवेदन सारांश तैयार किया है। कार्यक्षेत्र पैनल में इसे देखें और प्रिंट करें।`,
};

/** Shown when no schemes match the profile */
export const NO_SCHEMES_FOUND: Record<SupportedLanguage, string> = {
  en: "Based on the applicant's profile, no matching government schemes were found in our database.",
  hi: "आवेदक की प्रोफ़ाइल के आधार पर, हमारे डेटाबेस में कोई मिलान करने वाली सरकारी योजनाएं नहीं मिलीं।",
};
